import React, { useEffect, useState } from "react";
import { Pie, Bar } from "react-chartjs-2";
import "chart.js/auto";
import "./Dashboard.css";

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await fetch("/api/dashboard-stats");
        const data = await response.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching dashboard stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div>Loading dashboard data...</div>;

  const pieData = {
    labels: ["Free Rooms", "Occupied Rooms"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#4CAF50", "#F44336"],
      },
    ],
  };

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2196F3",
      },
    ],
  };

  return (
    <div className="dashboard-container">
      <h1 className="dashboard-title">📊 Classroom Availability Dashboard</h1>

      <div className="dashboard-top-grid">
        <div className="card chart-card">
          <h3>Free vs Occupied</h3>
          <Pie data={pieData} />
        </div>

        <div className="card small-chart-card">
          <h3>Performance</h3>
          <Pie data={pieData} options={{ cutout: "70%", plugins: { legend: { display: false } } }} />
        </div>

        <div className="card small-chart-card">
          <h3>Usage</h3>
          <Pie data={pieData} options={{ cutout: "70%", plugins: { legend: { display: false } } }} />
        </div>
      </div>

      <div className="card bar-chart-card">
        <h3>Free Rooms Per Day</h3>
        <Bar data={barData} />
      </div>

      <div className="card summary-card">
        <h3>Resource Summary</h3>
        <ul>
          <li><strong>Total Rooms:</strong> {stats.resources.totalRooms}</li>
          <li><strong>Labs:</strong> {stats.resources.labs}</li>
          <li><strong>Projector Rooms:</strong> {stats.resources.projectorRooms}</li>
          <li><strong>Classrooms:</strong> {stats.resources.classrooms}</li>
        </ul>
      </div>
    </div>
  );
};

export default Dashboard;
